const records = $input.first().json.result.records;

const filtered = records.filter(row =>
  row.type_expenditure1 === 'ค่าใช้จ่ายทั้งสิ้นต่อเดือน' ||
  row.type_expenditure2 === 'ค่าใช้จ่ายทั้งสิ้นต่อเดือน'
);

return filtered.map(row => ({ json: row }));

const records = $input.first().json.result.records;

const filtered = records.filter(row =>
  row.hhdebt_totaldebt === 'จำนวนหนี้สินเฉลี่ยต่อครัวเรือน' &&
  row.unit !== 'ครัวเรือน'
);

return filtered.map(row => ({ json: row }));

const items = $input.all();

// ใช้สำหรับรวมข้อมูลตาม province + year + soc_eco_class
const grouped = {};

items.forEach(item => {
  const row = item.json;

  const key = [
    row.year,
    row.province,
    row.soc_eco_class1,
    row.soc_eco_class2
  ].join('|');

  if (!grouped[key]) {
    grouped[key] = {
      province: row.province,
      year: row.year,
      soc_eco: row.soc_eco_class1,
      soc_eco2: row.soc_eco_class2,
      total_expense: 0,
      total_debt: 0
    };
  }

  const value = Number(row.value) || 0;

  // ค่าใช้จ่ายรวมต่อเดือน
  const isTotalExpense =
    row.type_expenditure1 === 'ค่าใช้จ่ายทั้งสิ้นต่อเดือน' &&
    row.type_expenditure2 === 'ค่าใช้จ่ายทั้งสิ้นต่อเดือน' &&
    row.unit === 'บาท';

  // หนี้สินรวมเฉลี่ยต่อครัวเรือน
  const isTotalDebt =
    row.hhdebt_totaldebt === 'จำนวนหนี้สินเฉลี่ยต่อครัวเรือน' &&
    row.hhdebt_totaldebt_purpose_source === 'จำนวนหนี้สินเฉลี่ยต่อครัวเรือน' &&
    row.purpose_source_bor === 'จำนวนหนี้สินเฉลี่ยต่อครัวเรือน' &&
    row.unit === 'บาท';

  if (isTotalExpense) {
    grouped[key].total_expense = value;
  }

  if (isTotalDebt) {
    grouped[key].total_debt = value;
  }
});

// แปลง object เป็น array
const analyzed = Object.values(grouped)
  .map(row => {
    const monthlyDebt = row.total_debt / 12;
    const debtToExpensePct =
      row.total_expense > 0
        ? (monthlyDebt / row.total_expense) * 100
        : 0;

    return {
      province: row.province,
      year: row.year,
      soc_eco: row.soc_eco,
      soc_eco2: row.soc_eco2,
      total_expense: row.total_expense,
      total_debt: row.total_debt,
      debt_to_expense_pct: Number(debtToExpensePct.toFixed(2))
    };
  })
  // เอาเฉพาะรายการที่มีทั้ง expense และ debt
  .filter(row => row.total_expense > 0 || row.total_debt > 0);

// Sort by debt_to_expense_pct มากไปน้อย
analyzed.sort((a, b) => b.debt_to_expense_pct - a.debt_to_expense_pct);

// Top 5 and Bottom 5
const top5 = analyzed.slice(0, 5);
const bottom5 = analyzed.slice(-5).reverse();

// Format email report
let report = '# Household Debt-to-Expense Analysis Report\n\n';

report += '## Top 5 Provinces with Highest Debt Burden\n\n';
top5.forEach((item, idx) => {
  report += `${idx + 1}. ${item.province} (${item.year}) - ${item.soc_eco2}\n`;
  report += `   Monthly Expense: ฿${item.total_expense.toLocaleString()}\n`;
  report += `   Total Debt: ฿${item.total_debt.toLocaleString()}\n`;
  report += `   Debt-to-Expense Ratio: ${item.debt_to_expense_pct}%\n\n`;
});

report += '\n## Bottom 5 Provinces with Lowest Debt Burden\n\n';
bottom5.forEach((item, idx) => {
  report += `${idx + 1}. ${item.province} (${item.year}) - ${item.soc_eco2}\n`;
  report += `   Monthly Expense: ฿${item.total_expense.toLocaleString()}\n`;
  report += `   Total Debt: ฿${item.total_debt.toLocaleString()}\n`;
  report += `   Debt-to-Expense Ratio: ${item.debt_to_expense_pct}%\n\n`;
});

report += `\n---\nTotal Records Analyzed: ${analyzed.length}\n`;
report += `Report Generated: ${new Date().toLocaleString('th-TH')}\n`;

return [
  {
    json: {
      report,
      top5,
      bottom5,
      all_data: analyzed
    }
  }
];
